            $b2p_filter = $this->db->placehold("AND o.b2p IN (?@)", array_map('intval', (array)$filter['b2p']));

        if (!empty($filter['current']))
            $current_filter = $this->db->placehold("AND (o.manager_id = ? OR (o.manager_id IS NULL AND o.status = 1))", (int)$filter['current']);

        if (!empty($filter['date_from'])) {
            $_date_from = (new DateTime($filter['date_from']))->format('Y-m-d');
            $date_from_filter = $this->db->placehold("AND o.date >= ?", $_date_from);
        }

        if (!empty($filter['date_to'])) {
            $_date_to = (new DateTime($filter['date_to']))->add(new DateInterval('P1D'))->format('Y-m-d');
            $date_to_filter = $this->db->placehold("AND o.date < ?", $_date_to);
        }

        if (isset($filter['autoretry']))
        {
            if (empty($filter['autoretry']))
                $autoretry_filter = $this->db->placehold("AND ((o.autoretry = ? OR o.autoretry IS NULL) OR (status != 1 AND o.autoretry = 1))", (int)$filter['autoretry']);
            else
                $autoretry_filter = $this->db->placehold("AND o.autoretry = ?", (int)$filter['autoretry']);
        }

        if (!empty($filter['filter_client'])) {
            if ($filter['filter_client'] === 'nk') {
                $filter_client = "AND o.have_close_credits != 1";
            } elseif($filter['filter_client'] === 'pk') {
                $filter_client = "AND o.have_close_credits = 1";
            }
        } else {
            $filter_client = '';
        }

        if (!empty($filter['loan_type'])) {
            if ($filter['loan_type'] === self::LOAN_TYPE_RCL) {
                $order_data_rcl_join = $this->db->placehold('INNER JOIN s_order_data od ON o.id = od.order_id AND od.`key` = ? AND value = ?', $this->order_data::RCL_LOAN, 1);
            } else {
                $loan_type_filter = $this->db->placehold('AND o.loan_type = ?', (string)$filter['loan_type']);
            }
        }

        // Фильтр тестовых заявок для верификаторов
        if (!empty($filter['hide_test_orders'])) {
            $hide_test_orders_filter = $this->db->placehold('AND (test_user_data.value IS NULL OR test_user_data.value = ?)', '0');
        }

        // Orders with status 'Не удалось выдать'
        if (isset($filter['failed_to_issue'])) {
            $search_filter .= $this->db->placehold(' AND status = ?', 11);
        }

        if (!empty($filter['not_company_orders'])) {
            $search_filter .= $this->db->placehold(' AND o.utm_source != ?', $this->orders::UTM_SOURCE_COMPANY_FORM);
        }

        if (!empty($filter['search']))
        {
            if (!empty($filter['search']['order_id']))
                $search_filter .= $this->db->placehold(' AND o.id = ?', (int)$filter['search']['order_id']);
            if (!empty($filter['search']['date']))
                $search_filter .= $this->db->placehold(' AND DATE(o.date) = ?', date('Y-m-d', strtotime($filter['search']['date'])));
            if (!empty($filter['search']['amount']))
                $search_filter .= $this->db->placehold(' AND o.amount = ?', (int)$filter['search']['amount']);
            if (!empty($filter['search']['period']))
                $search_filter .= $this->db->placehold(' AND o.period = ?', (int)$filter['search']['period']);
            if (!empty($filter['search']['fio']))
            {
                $fio_filter = array();
                $expls = array_map('trim', explode(' ', $filter['search']['fio']));
                $search_filter .= $this->db->placehold(' AND (');
                foreach ($expls as $expl)
                {
                    $expl = $this->db->escape($expl);
                    $fio_filter[] = $this->db->placehold("(u.lastname LIKE '%".$expl."%' OR u.firstname LIKE '%".$expl."%' OR u.patronymic LIKE '%".$expl."%')");
                }
                $search_filter .= implode(' AND ', $fio_filter);
