            endswitch;
        }


/* кредитный рейтинг
        $filter_no_scoring = '';
        if (!empty($filter['search']['credit_rating'])) {
            $exist = in_array($filter['search']['credit_rating'], [2, 3]) ? 'EXISTS' : 'NOT EXISTS';
            $has_credit_rating = (int)(in_array($filter['search']['credit_rating'], [2, 3]));
