                u.Faktindex,
                u.Faktregion,
                u.Faktregion_shorttype,
                u.Faktcity,
                u.Faktcity_shorttype,
                u.Faktstreet,
                u.Faktstreet_shorttype,
                u.Fakthousing,
                u.Faktbuilding,
                u.Faktroom,
                u.contact_person_name,
