                u.utm_source AS client_utm_source,
                crm_response,
                $autoApproveSelect as auto_approve,
                $userTimezoneSelect as timezone
                $lastCallSelect
            FROM __orders AS o
            LEFT JOIN __users AS u ON u.id = o.user_id
            $autoApproveJoin
            $userTimezoneJoin
            $not_scor_approve_join
            $test_user_join
            $order_data_rcl_join
