    public function count_orders($filter = array())
    {
        // Создаем уникальный ключ кэша на основе всех переданных фильтров
        $cache_key = "orders:count:" . md5(serialize($filter));

        return $this->caches->wrap($cache_key, 30, function () use ($filter) {
            $id_filter = '';

            $manager_id_filter = '';
            $not_manager_id_filter = '';
            $user_id_filter = '';
            $current_filter = '';
            $status_filter = '';
            $not_status_1c_filter = '';
            $notbusy_filter = '';
            $inwork_filter = '';
            $notreceived_filter = '';
            $approve_filter = '';
            $approve_period_filter = '';
            $issued_filter = '';
            $stage_completed_filter = '';
            $date_from_filter = '';
            $date_to_filter = '';
            $search_filter = '';
            $dops_filter = '';
            $cdoctor_filter = '';
            $close_credits_filter = '';
            $credit_getted_filter = '';
            $autoretry_filter = '';
            $keyword_filter = '';
            $credit_doctor_filter = '';
            $completed_scorings_filter = '';
            $filter_user_registered = '';
            $hasNotReceivedManagerFilter = '';
            $notReceivedLoanManagerId = '';
            $loan_type_filter = '';
            $organizations_filter = '';
            $user_join = '';

            if (!empty($filter['completed_scorings']))
                $completed_scorings_filter = $this->db->placehold("AND o.id NOT IN (SELECT order_id FROM s_scorings WHERE manual = 0 AND status IN (?, ?, ?))",
                    $this->scorings::STATUS_NEW, $this->scorings::STATUS_PROCESS, $this->scorings::STATUS_IMPORT);

            if (isset($filter['close_credits']))
                $close_credits_filter = $this->db->placehold("AND o.have_close_credits = ?", (int)$filter['close_credits']);

            if (isset($filter['credit_getted']))
                $credit_getted_filter = $this->db->placehold("AND o.credit_getted = ?", (int)$filter['credit_getted']);

            if (isset($filter['cdoctor'])) {
                if (empty($filter['cdoctor']))
                    $cdoctor_filter = $this->db->placehold("AND (o.cdoctor_id = 0 OR o.cdoctor_id IS NULL)");
                else
                    $cdoctor_filter = $this->db->placehold("AND o.cdoctor_id > 0");
            }

            if (!empty($filter['dops'])) {
                $dops_filter = $this->db->placehold("AND (u.service_insurance = 1 OR (u.service_insurance = 0 AND o.have_close_credits = 1) OR o.is_credit_doctor = 1)");
                $need_join_users = 1;
            }

            if (isset($filter['credit_doctor']) && $filter['credit_doctor']) {
//            $credit_doctor_filter = $this->db->placehold("AND (o.is_credit_doctor = 1 OR o.is_credit_doctor = 0)");
            } else {
//            $credit_doctor_filter = $this->db->placehold("AND o.is_credit_doctor = 0");
            }

            if (!empty($filter['id']))
                $id_filter = $this->db->placehold("AND o.id IN (?@)", array_map('intval', (array)$filter['id']));

            if (!empty($filter['status']))
                $status_filter = $this->db->placehold("AND o.status IN (?@)", (array)$filter['status']);

            if (!empty($filter['notreceived']))
                $notreceived_filter = $this->db->placehold("AND o.status = 2 AND o.confirm_date IS NULL AND o.1c_status != '5.Выдан' AND o.1c_status != '6.Закрыт'");

            if (!empty($filter['approve']))
                $approve_filter = $this->db->placehold("AND o.status = 2 AND o.confirm_date IS NULL AND o.1c_status != '5.Выдан' AND o.1c_status != '6.Закрыт'");

            if (!empty($filter['approve_period'])) {
                $approve_period_filter = $this->db->placehold("AND NOW() < o.approve_date + interval 7 day");
            }

            if (!empty($filter['notbusy']))
                $notbusy_filter = $this->db->placehold("AND (o.manager_id = 0 OR o.manager_id IS NULL) AND status = 1");

            if (!empty($filter['issued']))
                $issued_filter = $this->db->placehold("AND ((o.status = 2 AND (o.confirm_date IS NOT NULL OR o.1c_status = '5.Выдан')) OR o.status = 10)");

            if (!empty($filter['inwork']))
                $inwork_filter = $this->db->placehold("AND o.manager_id != 0 AND o.manager_id IS NOT NULL AND status = 1");

            if (!empty($filter['not_status_1c']))
                $not_status_1c_filter = $this->db->placehold("AND (o.1c_status NOT IN (?@) OR o.1c_status IS NULL)", (array)$filter['not_status_1c']);

            if (!empty($filter['stage_completed']) || !empty($filter['filter_stage_completed']))
                $stage_completed_filter = $this->db->placehold("AND (o.complete = 1 OR EXISTS (SELECT 1 FROM s_order_data od WHERE od.order_id = o.id AND od.`key` = 'is_sold_to_bonon'))");

            if (!empty($filter['manager_id']))
                $manager_id_filter = $this->db->placehold("AND o.manager_id = ?", (int)$filter['manager_id']);

            if (!empty($filter['not_manager_id']))
                $not_manager_id_filter = $this->db->placehold("AND (o.manager_id NOT IN (?@) OR o.manager_id IS NULL)", array_map('intval', (array)$filter['not_manager_id']));

            if (!empty($filter['user_id']))
                $user_id_filter = $this->db->placehold("AND o.user_id IN (?@)", array_map('intval', (array)$filter['user_id']));

            if (!empty($filter['organization_id']))
                $organizations_filter = $this->db->placehold("AND o.organization_id IN (?@)", array_map('intval', (array)$filter['organization_id']));

            if (!empty($filter['current']))
                $current_filter = $this->db->placehold("AND (o.manager_id = ? OR (o.manager_id IS NULL AND o.status = 1))", (int)$filter['current']);

            if (!empty($filter['date_from']))
                $date_from_filter = $this->db->placehold("AND DATE(o.date) >= ?", $filter['date_from']);

            if (!empty($filter['date_to']))
                $date_to_filter = $this->db->placehold("AND DATE(o.date) <= ?", $filter['date_to']);

            if (isset($filter['autoretry'])) {
                if (empty($filter['autoretry']))
                    $autoretry_filter = $this->db->placehold("AND ((o.autoretry = ? OR o.autoretry IS NULL) OR (status != 1 AND o.autoretry = 1))", (int)$filter['autoretry']);
                else
                    $autoretry_filter = $this->db->placehold("AND o.autoretry = ?", (int)$filter['autoretry']);
            }

            if (!empty($filter['has_not_received_loan_manager'])) {
                $hasNotReceivedManagerFilter = $this->db->placehold('AND o.not_received_loan_manager_id > 0');
            }

            if (!empty($filter['loan_type'])) {
                $loan_type_filter = $this->db->placehold('AND o.loan_type = ?', (string)$filter['loan_type']);
            }

            if (!empty($filter['not_received_loan_manager_id'])) {
                $notReceivedLoanManagerId = $this->db->placehold(
                    'AND o.not_received_loan_manager_id = ?',
                    (int)$filter['not_received_loan_manager_id']
                );
            }

            if (!empty($filter['filter_client'])) {
                if ($filter['filter_client'] === 'nk') {
                    $filter_client = "AND o.have_close_credits != 1";
                } elseif ($filter['filter_client'] === 'pk') {
                    $filter_client = "AND o.have_close_credits = 1";
                }
            } else {
                $filter_client = '';
            }

            // отвалы в рамках 1 дня
            if (!empty($filter['filter_user_registered'])) {
                $filter_user_registered = " AND IF(o.have_close_credits = 0, (
                        u.personal_data_added = 1 AND DATE(u.personal_data_added_date) = DATE(o.date)
                    AND u.address_data_added = 1 AND DATE(u.additional_data_added_date) = DATE(o.date)
                    AND u.accept_data_added = 1 AND DATE(u.accept_data_added_date) = DATE(o.date)
                    AND u.card_added = 1 AND DATE(u.card_added_date) = DATE(o.date)
                    AND u.files_added = 1 AND DATE(u.files_added_date) = DATE(o.date)
                    AND u.additional_data_added = 1 AND DATE(u.additional_data_added_date) = DATE(o.date)), 1)";
                $need_join_users = 1;
            }

            if (!empty($filter['not_company_orders'])) {
                $search_filter .= $this->db->placehold(' AND o.utm_source != ?', $this->orders::UTM_SOURCE_COMPANY_FORM);
            }

            if (!empty($filter['search'])) {
                if (!empty($filter['search']['order_id']))
                    $search_filter .= $this->db->placehold(' AND o.id = ?', (int)$filter['search']['order_id']);
                if (!empty($filter['search']['date']))
                    $search_filter .= $this->db->placehold(' AND DATE(o.date) = ?', date('Y-m-d', strtotime($filter['search']['date'])));
                if (!empty($filter['search']['amount']))
                    $search_filter .= $this->db->placehold(' AND o.amount = ?', (int)$filter['search']['amount']);
                if (!empty($filter['search']['period']))
                    $search_filter .= $this->db->placehold(' AND o.period = ?', (int)$filter['search']['period']);
                if (!empty($filter['search']['fio'])) {
                    $fio_filter = array();
                    $expls = array_map('trim', explode(' ', $filter['search']['fio']));
                    $search_filter .= $this->db->placehold(' AND (');
                    foreach ($expls as $expl) {
                        $expl = $this->db->escape($expl);
                        $fio_filter[] = $this->db->placehold("(u.lastname LIKE '%" . $expl . "%' OR u.firstname LIKE '%" . $expl . "%' OR u.patronymic LIKE '%" . $expl . "%')");
                    }
                    $search_filter .= implode(' AND ', $fio_filter);
                    $search_filter .= $this->db->placehold(')');
                    $need_join_users = 1;
                }
                if (!empty($filter['search']['birth'])) {
                    $search_filter .= $this->db->placehold(' AND DATE(u.birth) = ?', date('Y-m-d', strtotime($filter['search']['birth'])));
                    $need_join_users = 1;
                }
                if (!empty($filter['search']['phone'])) {
                    $search_filter .= $this->db->placehold(" AND u.phone_mobile LIKE '%" . $this->db->escape(str_replace(array(' ', '-', '(', ')', '+'), '', $filter['search']['phone'])) . "%'");
                    $need_join_users = 1;
                }
                if (!empty($filter['search']['region'])) {
                    $search_filter .= $this->db->placehold(" AND u.Regregion LIKE '%" . $this->db->escape($filter['search']['region']) . "%'");
                    $need_join_users = 1;
                }
                if (!empty($filter['search']['manager_id']))
                    $search_filter .= $this->db->placehold(" AND o.manager_id = ?", (int)$filter['search']['manager_id']);
                if (!empty($filter['search']['status']))
                    $search_filter .= $this->db->placehold(" AND o.1c_status LIKE '%" . $this->db->escape($filter['search']['status']) . "%'");
                if (!empty($filter['search']['utm']))
                    $search_filter .= $this->db->placehold(" AND (o.utm_source LIKE '%" . $this->db->escape($filter['search']['utm']) . "%' OR o.webmaster_id LIKE '%" . $this->db->escape($filter['search']['utm']) . "%')");
                if (!empty($filter['search']['reason'])) {
                    if ($filter['search']['reason'] === 'is_null') {
                        $search_filter .= $this->db->placehold(" AND (o.reason_id IS NULL OR o.reason_id = '')");
                    } else {
                        $search_filter .= $this->db->placehold(" AND o.reason_id = ?", (int)$filter['search']['reason']);
                    }
                }
            }

            if (!empty($filter['filter_utm_source']) && !in_array('all', $filter['filter_utm_source'])) {
                $search_filter .= $this->db->placehold(" AND (o.utm_source IN(?@))", $filter['filter_utm_source']);
            }

            // Фильтр исключающий utm метки
            if (!empty($filter_data['filter_without_utm_source'])) {
                $search_filter .= $this->db->placehold(" AND (o.utm_source NOT IN (?@))", $filter_data['filter_without_utm_source']);
            }

            // Orders with status 'Не удалось выдать'
            if (isset($filter['failed_to_issue'])) {
                $search_filter .= $this->db->placehold(' AND status = ?', 11);
            }

            if (isset($filter['keyword'])) {
                $keywords = explode(' ', $filter['keyword']);
                foreach ($keywords as $keyword)
                    $keyword_filter .= $this->db->placehold('AND (name LIKE "%' . $this->db->escape(trim($keyword)) . '%" )');
            }

            $filter_no_scoring = '';

            if (!empty($filter['search']['credit_rating'])) {
                $exist = in_array($filter['search']['credit_rating'], [2, 3]) ? 'EXISTS' : 'NOT EXISTS';
                $where_credit_rating = " AND " . $exist . " (SELECT 
                    *
                FROM 
                    __transactions tr
                WHERE 
                    tr.user_id = u.id 
                    AND tr.payment_type = 'credit_rating'
                    AND tr.status IN('CONFIRMED', 'AUTHORIZED'))";


                if (in_array($filter['search']['credit_rating'], [2, 3])) {
                    $exist_scorings = $filter['search']['credit_rating'] == 3 ? 'EXISTS' : 'NOT EXISTS';
                    $filter_no_scoring = " AND " . $exist_scorings . " (SELECT 
                    *
                FROM __scorings sc
                WHERE
                sc.user_id = o.user_id
                AND sc.type = " . $this->scorings::TYPE_SCORISTA . " 
                -- AND sc.status = " . $this->scorings::STATUS_COMPLETED . "
                )";
                }
                $need_join_users = 1;

            } else {
                $where_credit_rating = '';
            }

            if (!empty($need_join_users)) {
                $user_join = "LEFT JOIN __users AS u ON u.id = o.user_id";
            }

            $not_scor_approve_join = $this->db->placehold("
                LEFT JOIN s_order_data scor_approve_exclude ON
                scor_approve_exclude.order_id = o.id
                AND scor_approve_exclude.`key` = ?
                AND scor_approve_exclude.`value` != 0
            ", $this->order_data::SCOR_APPROVE);
            $exclude_scor_approve_filter = "AND scor_approve_exclude.order_id IS NULL";

            $query = $this->db->placehold("
            SELECT COUNT(o.id) AS count
            FROM __orders AS o
            $user_join
            $not_scor_approve_join
            WHERE 1
                $id_filter
                $manager_id_filter
                $not_manager_id_filter
                $user_id_filter
                $notbusy_filter
                $current_filter
                $status_filter
                $notreceived_filter
                $approve_filter
                $approve_period_filter
                $issued_filter
                $inwork_filter
                $stage_completed_filter
                $not_status_1c_filter
                $date_from_filter
                $date_to_filter
                $search_filter
                $dops_filter 
                $cdoctor_filter               
                $close_credits_filter
                $credit_getted_filter
                $credit_doctor_filter
                $autoretry_filter
                $keyword_filter
                $where_credit_rating
                $filter_no_scoring
                $completed_scorings_filter
                $filter_client
                $filter_user_registered
                $hasNotReceivedManagerFilter
                $notReceivedLoanManagerId
                $organizations_filter
                $loan_type_filter
                $exclude_scor_approve_filter
        ");
            $this->db->query($query);
            return $this->db->result('count');
        });
    }

    public function add_order($order)
    {
    	$order = (array)$order;

        if (empty($order['order_uid']))
            $order['order_uid'] = exec($this->config->root_dir.'generic/uidgen');

        $query = $this->db->placehold("
            INSERT INTO __orders SET ?%
        ", (array)$order);
        $this->db->query($query);
        $order_id = $this->db->insert_id();

        $this->spr_versions->markOrderVersion($order_id);

        return $order_id;
    }

    public function update_order($id, $order)
    {
        $update_data = (array)$order;

        // Получаем текущее состояние заказа один раз
        $order_old = $this->get_order($id);

        // Логируем только если изменилось поле amount
        if (
            isset($update_data['amount']) &&
            (int)$order_old->amount !== (int)$update_data['amount']
        ) {
            $bt = debug_backtrace(DEBUG_BACKTRACE_IGNORE_ARGS, 5);
            $caller_trace = [];

            foreach ($bt as $trace) {
                if (!empty($trace['file']) && !empty($trace['line'])) {
                    $caller_trace[] = "{$trace['file']}:{$trace['line']}" .
                        (isset($trace['function']) ? " in {$trace['function']}()" : '');
                }
            }

            $this->logging(
                __METHOD__,
                'amount changed',
                [
                    'order_id'   => $id,
                    'old_amount' => $order_old->amount,
                    'new_amount' => $update_data['amount'],
                    'caller'     => $caller_trace,
                ],
                'Изменение суммы заявки',
                'update_order_amount.txt'
            );
        }

        $query = $this->db->placehold("UPDATE __orders SET ?% WHERE id = ?", $update_data, (int)$id);
        $this->db->query($query);

        $this->onOrderUpdated((int)$id, $update_data, $order_old);

        return $id;
    }

    public function assignManager($orderId, $managerId): void
    {
        $now = date('Y-m-d H:i:s');

        $sql = "UPDATE __orders
            SET manager_id = ?, accept_date = ?, stage1 = 1, stage1_date = ?
            WHERE id = ? AND (manager_id IS NULL OR manager_id = 0)";

        $query = $this->db->placehold($sql, $managerId, $now, $now, $orderId);
        $this->db->query($query);
    }

    /**
     * Действие после обновления заявки
     *
     * @param int $order_id
     * @param array $update_data - Данные которые обновляли
     * @param $order_old - Старая не обновленная заявка
     * @return void
     */
    private function onOrderUpdated(int $order_id, array $update_data, $order_old)
    {
        // добавим отправку постбека если статус изменился на "Отказ"
        $old_status = (int)$order_old->status;
        if ($old_status !== 3 && ((int)($update_data['status'] ?? 0)) === 3) {
            //$this->post_back->sendReject($order_old);
        }

        if (
            (!empty($update_data['status']) && $order_old->status != $update_data['status']) ||
            (!empty($update_data['1c_status']) && $order_old->status_1c != $update_data['1c_status'])
        ) {
            $this->addStatusLog($order_id, $update_data, (array)$order_old);

            // При продаже карты отказного НК не отправляем никакие смс и не делаем переход на отказные витрины
            $is_bonon = (bool)$this->order_data->read($order_id, 'is_sold_to_bonon');
            // Самоотказ, клиенту бесполезно предлагать кредиты
            $is_self_dec = $order_old->reason_id == $this->reasons::REASON_SELF_DEC;
            if (!($is_bonon || $is_self_dec) && !empty($update_data['1c_status']))
                $this->push_token->addTasks($order_old, $update_data['1c_status']);
        }

        if(!empty($update_data['reject_date']) && (int)$order_old->status !== 3) {
            $this->updateOrderExternal($order_id);
        }

        // Если статус 1С изменился на "Закрыт" — включаем автосписания по картам и СБП
        if (
            !empty($update_data['1c_status'])
            && $update_data['1c_status'] === self::ORDER_1C_STATUS_CLOSED
            && $order_old->status_1c !== self::ORDER_1C_STATUS_CLOSED
        ) {
            $this->enableAutodebitsOnClose($order_id, (int)$order_old->user_id);
        }

        // Добавляем триггер, если заявка перешла в одобренную
        if ($this->isStatusApproveUpdated($old_status, $update_data)) {
            if ($autoconfirm_amount = $this->autoconfirm->get_amount($order_old)) {
                $this->autoconfirm->set_autoconfirm($autoconfirm_amount, $order_old);
            }
        }

        $newStatus = isset($update_data['status']) ? (int)$update_data['status'] : null;
        $newStatus1c = $update_data['1c_status'] ?? null;
        
        $isIssued =
            ($newStatus === self::ORDER_STATUS_CRM_ISSUED && $old_status !== self::ORDER_STATUS_CRM_ISSUED) ||
            ($newStatus1c === self::ORDER_1C_STATUS_ISSUED && $order_old->status_1c !== self::ORDER_1C_STATUS_ISSUED);

        if ($isIssued) {
            $this->user_data->set((int)$order_old->user_id, UserData::SHOW_CESSION_INFO);
            $this->user_data->set((int)$order_old->user_id, UserData::SHOW_AGENT_INFO);
        }
    }

    /**
     * Если новый статус Одобрено
     * @param int $old_status
     * @param array $update_data
     * @return bool
     */
    private function isStatusApproveUpdated(int $old_status, array $update_data): bool
    {
        return $old_status !== self::ORDER_STATUS_CRM_APPROVED && ((int)($update_data['status'] ?? 0)) === self::ORDER_STATUS_CRM_APPROVED;
    }

    /**
     * Включает автосписания по картам и СБП при закрытии договора в 1С
     * @param int $orderId
     * @param int $userId
     * @return void
     */
    private function enableAutodebitsOnClose(int $orderId, int $userId): void
    {
        try {
            $now = date('Y-m-d H:i:s');

            // Включаем автосписание по всем картам пользователя
            foreach ($this->best2pay->get_cards(['user_id' => $userId]) as $card) {
                if ((int)($card->autodebit ?? 0) === 1) {
                    continue;
                }

                try {
                    $this->best2pay->update_card($card->id, [
                        'autodebit' => 1,
                        'autodebit_changed_at' => $now,
                    ]);

                    // Лог действия
                    $this->best2pay->add_sbp_log([
                        'card_id' => $card->id,
                        'action' => self::CARD_ACTIONS['AUTODEBIT_CARD_ON'],
                        'date' => $now,
                    ]);

                    // Changelog
                    $this->changelogs->add_changelog([
                        'manager_id' => $this->managers::MANAGER_SYSTEM_ID,
                        'created' => $now,
                        'type' => 'autodebit',
                        'old_values' => serialize(['autodebit' => $card->autodebit]),
                        'new_values' => serialize(['autodebit' => 1]),
                        'order_id' => $orderId,
                        'user_id' => $userId,
                    ]);
                } catch (\Throwable $e) {
                    error_log('[enableAutodebitsOnClose][CARD enable] user_id=' . $userId . ', card_id=' . $card->id . ', error=' . $e->getMessage());
                }
            }

            // Включаем автосписание по всем СБП-счётам пользователя
            $sbpAccounts = $this->users->getSbpAccounts($userId);
            if (!empty($sbpAccounts)) {
                foreach ($sbpAccounts as $sbpAccount) {
                    if ((int)($sbpAccount->autodebit ?? 0) === 1) {
                        continue;
                    }

                    try {
                        $this->best2pay->updateSbpAccount((string)$sbpAccount->id, [
                            'autodebit' => 1,
                            'autodebit_changed_at' => $now,
                        ]);

                        // Лог действия
                        $this->best2pay->add_sbp_log([
                            'card_id' => $sbpAccount->id,
                            'action' => self::CARD_ACTIONS['AUTODEBIT_SBP_ON'],
                            'date' => $now,
                        ]);

                        // Changelog
                        $this->changelogs->add_changelog([
                            'manager_id' => $this->managers::MANAGER_SYSTEM_ID,
                            'created' => $now,
                            'type' => 'autodebit',
                            'old_values' => serialize(['autodebit' => $sbpAccount->autodebit]),
                            'new_values' => serialize(['autodebit' => 1]),
                            'order_id' => $orderId,
                            'user_id' => $userId,
                        ]);
                    } catch (\Throwable $e) {
                        error_log('[enableAutodebitsOnClose][SBP enable] user_id=' . $userId . ', sbp_account_id=' . $sbpAccount->id . ', error=' . $e->getMessage());
                    }
                }
            }
        } catch (\Throwable $e) {
            error_log('[enableAutodebitsOnClose] user_id=' . $userId . ', order_id=' . $orderId . ', error=' . $e->getMessage());
        }
    }

