    /**
     * Получаем количество заявок за текущий день вместе с суммой КД
     * @param string|null $site_id
     * @return array|false
     */
    public function getOrdersForCurrentDay($site_id = null)
    {
        $site_id_filter = '';
        if (!empty($site_id)) {
            $site_id_filter = $this->db->placehold("AND u.site_id = ?", $site_id);
        }

        $query = $this->db->placehold("
            SELECT 
                p.id, 
                o.id as order_id,
                o.have_close_credits,
                o.organization_id,
                o.utm_source,
                o.utm_term,
                c.amount
            FROM b2p_p2pcredits as p
            LEFT JOIN s_orders AS o
            ON o.id = p.order_id
            LEFT JOIN s_contracts AS c
            ON c.order_id = p.order_id
            LEFT JOIN s_users AS u
            ON u.id = o.user_id
            WHERE p.status = 'APPROVED'
            AND p.complete_date >= ?
            AND p.complete_date <= ?
            $site_id_filter
        ", date('Y-m-d 00:00:00'), date('Y-m-d 23:59:59'));
        $this->db->query($query);

        return $this->db->results();
    }

