    /**
     * Получает общее кол-во заявок по временному интервалу и фильтру
     * Метод для аналитика
     * @param array $filter_data
     * @return array|false
     */
    public function getTotalOrdersForAnalytic(array $filter_data = [])
    {
        $select = [];
        $where = [];
        $join = [];

        $query =
            "SELECT 
                COUNT(*) as total,
                -- {{select}}
                FROM 
                    s_orders o LEFT JOIN s_users u ON u.id = o.user_id
                    LEFT JOIN s_postback as p ON p.order_id = o.id AND p.type = 'hold'
                -- {{join}}
            WHERE 
              DATE(o.date) BETWEEN ? AND ?
                -- {{where}}
              GROUP BY filter_date
        ";

        if (!empty($filter_data['filter_group_by'])) {
            if ($filter_data['filter_group_by'] === 'day') {
                $select[] = "DATE_FORMAT(o.date, '%Y.%m.%d') as filter_date";
            } elseif ($filter_data['filter_group_by'] === 'month') {
                $select[] = "DATE_FORMAT(o.date, '%Y.%m') as filter_date";
            }
        }

        if (!empty($filter_data['filter_date_accept'])) {
            $where[] = $this->db->placehold("additional_data_added = 1");
        }

        if (!empty($filter_data['filter_date_approved'])) {
            $where[] = $this->db->placehold("o.approve_date BETWEEN ? AND ?", $filter_data['filter_date_start']->format('Y-m-d 00:00:00'), $filter_data['filter_date_end']->format('Y-m-d 23:59:59'));
        }

        if (!empty($filter_data['filter_date_confirm'])) {
            $where[] = $this->db->placehold("o.confirm_date BETWEEN ? AND ?", $filter_data['filter_date_start']->format('Y-m-d 00:00:00'), $filter_data['filter_date_end']->format('Y-m-d 23:59:59'));
        }

        if (!empty($filter_data['filter_additional_data_added_date'])) {
            $where[] = $this->db->placehold("u.additional_data_added_date BETWEEN ? AND ?", $filter_data['filter_date_start']->format('Y-m-d 00:00:00'), $filter_data['filter_date_end']->format('Y-m-d 23:59:59'));
        }

        if (!empty($filter_data['filter_webmaster_id'])) {
            $where[] = $this->db->placehold("o.webmaster_id IN (?@)", $filter_data['filter_webmaster_id']);
        }

        if (!empty($filter_data['filter_status'])) {
            // 2 - одобрена
            //$where[] = " o.status = " . (int)$filter_data['filter_status'];

            // если принята
            if (!empty($filter_data['filter_status_accept'])) {
                $where[] = " o.accept_date IS NOT NULL";
            }

            // если одобрена
            if (!empty($filter_data['filter_status_approved'])) {
                $where[] = " o.approve_date IS NOT NULL";
            }

            // если выдана
            if (!empty($filter_data['filter_status_issued'])) {
                $where[] = "o.confirm_date IS NOT NULL";

                if (!empty($filter_data['filter_no_validate_postback'])) {
                    $where[] = $this->db->placehold("IF(o.utm_source IN (?@), 1, o.leadgen_postback IS NOT NULL)", $filter_data['filter_no_validate_postback']);
                }
            }
        }

        if (!empty($filter_data['filter_utm_source'])) {
            $where[] = $this->db->placehold("o.utm_source = ?", $filter_data['filter_utm_source']);
        }

        if (!empty($filter_data['filter_utm_sources'])) {
            $where[] = $this->db->placehold("o.utm_source IN (?@)", $filter_data['filter_utm_sources']);
        }

        if (isset($filter_data['filter_client_type'])) {
            $where[] = $this->db->placehold("o.have_close_credits = ?", $filter_data['filter_client_type']);
        }

        if (!empty($filter_data['filter_user_registered'])) {
            $where[] = "(
                u.personal_data_added = 1 AND DATE(u.personal_data_added_date) = DATE(o.date)
                AND u.address_data_added = 1 AND DATE(u.additional_data_added_date) = DATE(o.date)
                AND u.accept_data_added = 1 AND DATE(u.accept_data_added_date) = DATE(o.date)
                AND u.card_added = 1 AND DATE(u.card_added_date) = DATE(o.date)
                AND u.files_added = 1 AND DATE(u.files_added_date) = DATE(o.date)
                AND u.additional_data_added = 1 AND DATE(u.additional_data_added_date) = DATE(o.date)
            )";
        }

        $query = strtr($query, [
            '-- {{select}}' => !empty($select) ? implode("\n", $select) : '',
            '-- {{join}}' => !empty($join) ? implode("\n", $join) : '',
            '-- {{where}}' => !empty($where) ? "AND " . implode(" AND ", $where) : '',
        ]);

        $sql = $this->db->placehold($query, $filter_data['filter_date_start']->format('Y-m-d'), $filter_data['filter_date_end']->format('Y-m-d'));

        $this->db->query($sql);
        return $this->db->results();
    }

