    /**
     * Получает кол-во отказов для отчёта
     * @param array $filter_data
     * @return array|false
     */
    public function getRejectedOrders(array $filter_data = [])
    {
        $select = [];
        $where = [];
        $join = [];
        $group_by = "GROUP BY o.reason_id \n ORDER BY o.reason_id ASC";

        $sql =
            "SELECT 
                COUNT(*) as total,
                o.reason_id,
                r.admin_name
                -- {{select}}
                FROM 
                    s_orders o LEFT JOIN s_reasons r ON r.id = o.reason_id
                -- {{join}}
            WHERE 
                o.status = 3
              AND DATE(o.date) BETWEEN ? AND ?
                -- {{where}}
                -- {{group_by}}
        ";

        if (!empty($filter_data['filter_group_by'])) {
            if ($filter_data['filter_group_by'] === 'day') {
                $select[] = ", DATE_FORMAT(o.reject_date, '%Y.%m.%d') as filter_date";
            }
        }

        if (!empty($filter_data['filter_utm_source'])) {
            $where[] = $this->db->placehold("o.utm_source IN (?@)", $filter_data['filter_utm_source']);
        }

        // Фильтр исключающий utm метки
        if (!empty($filter_data['filter_without_utm_source'])) {
            $where[] = $this->db->placehold("o.utm_source NOT IN (?@)", $filter_data['filter_without_utm_source']);
        }

        if (!empty($filter_data['filter_client']) && $filter_data['filter_client'] !== 'ALL') {
            $filter_client = (int)($filter_data['filter_client'] === 'PK');
            $where[] = "o.have_close_credits = " . $filter_client;
        }

        // полностью зарегистрирован
        if (!empty($filter_data['filter_stage_completed']))
        {
            $where[] = $this->db->placehold("u.additional_data_added = 1");
            $where[] = $this->db->placehold("(o.complete = 1 OR EXISTS (SELECT 1 FROM s_order_data od WHERE od.order_id = o.id AND od.`key` = 'is_sold_to_bonon'))");
        }

        // исключаем отвалы
        if (!empty($filter_data['filter_user_registered'])) {
            $where[] =  $this->db->placehold("o.complete = 0");
        }

        if (!empty($filter_data['filter_user_registered']) || !empty($filter_data['filter_stage_completed']))
        {
            $join[] = "LEFT JOIN s_users u ON u.id = o.user_id";
        }

        $query = strtr($sql, [
            '-- {{join}}' => !empty($join) ? implode(PHP_EOL, $join) : '',
            '-- {{select}}' => !empty($select) ? implode("\n", $select) : '',
            '-- {{where}}' => !empty($where) ? "AND " . implode(" AND ", $where) : '',
            '-- {{group_by}}' => $group_by,
        ]);

        $query = $this->db->placehold($query, $filter_data['filter_date_order']['filter_date_start'], $filter_data['filter_date_order']['filter_date_end']);

        $this->db->query($query);
        return $this->db->results();
    }

    /**
     * Получает общее кол-во заявок
     * @param array $filter_data
     * @param bool $return_ids
     * @param string $fields
     * @return array|false|int
     */
    public function getTotalOrders(array $filter_data = [], bool $return_ids = false, string $fields = '')
    {
        $where = [];
        $join = [];
        $return_fields = !empty($fields) ? $fields : ($return_ids ? 'o.id' : 'COUNT(*) as total');

        $sql =
            "SELECT 
                $return_fields
                FROM 
                    s_orders o
                -- {{join}}
            WHERE 1 = 1
                -- {{where}}
        ";

        // Фильтр по utm_source
        if (!empty($filter_data['filter_utm_source'])) {
            $where[] = $this->db->placehold("o.utm_source IN (?@)", $filter_data['filter_utm_source']);
        }

        // Фильтр исключающий utm метки
        if (!empty($filter_data['filter_without_utm_source'])) {
            $where[] = $this->db->placehold("o.utm_source NOT IN (?@)", $filter_data['filter_without_utm_source']);
        }

        // Фильтр по webmaster_id
        if (!empty($filter_data['filter_webmaster_id'])) {
            $where[] = $this->db->placehold("o.webmaster_id IN (?@)", $filter_data['filter_webmaster_id']);
        }

        // фильтр по ПК или НК
        if (!empty($filter_data['filter_client']) && $filter_data['filter_client'] !== 'ALL') {
            $filter_client = (int)($filter_data['filter_client'] === 'PK');
            $where[] = "o.have_close_credits = " . $filter_client;
        }

        // одобрено по наличию даты или он же факт одобрения
        if (!empty($filter_data['filter_is_approved'])) {
            $where[] = "(o.approve_date IS NOT NULL AND o.approve_date != '')";
        }

        // включить статус 1с
        if (!empty($filter_data['1с_status'])) {
            $where[] = $this->db->placehold("o.1c_status = ?", $filter_data['1с_status']);
        }

        // исключаем статусы
        if (!empty($filter_data['not_1с_statuses'])) {
            $where[] = $this->db->placehold("o.1c_status NOT IN(?@)", $filter_data['not_1с_statuses']);
        }

        // включить статус CRM
        if (!empty($filter_data['status'])) {
            $where[] = "o.status = " . (int)$filter_data['status'];
        }

        // исключить статусы CRM
        if (!empty($filter_data['not_statuses'])) {
            $where[] = $this->db->placehold("o.status NOT IN(?@)", $filter_data['not_statuses']);
        }

        // выдано по наличию даты или он же факт выдачи
        if (!empty($filter_data['filter_is_confirmed'])) {
            $where[] = "(o.confirm_date IS NOT NULL AND o.confirm_date != '')";
        }

        // даты заявки
        if (!empty($filter_data['filter_date_order'])) {
            $where[] = $this->db->placehold("DATE(o.date) BETWEEN ? AND ?", $filter_data['filter_date_order']['filter_date_start'], $filter_data['filter_date_order']['filter_date_end']);
        }

        // дата выдачи
        if (!empty($filter_data['filter_date_confirm'])) {
            $where[] = $this->db->placehold("DATE(o.confirm_date) BETWEEN ? AND ?", $filter_data['filter_date_confirm']['filter_date_start'], $filter_data['filter_date_confirm']['filter_date_end']);
        }

        // дата одобрения
        if (!empty($filter_data['filter_date_approve'])) {
            $where[] = $this->db->placehold("DATE(o.approve_date) BETWEEN ? AND ?", $filter_data['filter_date_approve']['filter_date_start'], $filter_data['filter_date_approve']['filter_date_end']);
        }

        // исключить причины отказа
        if (!empty($filter_data['not_reason_ids'])) {
            $where[] = $this->db->placehold("(o.reason_id NOT IN(?@) AND o.reason_id IS NOT NULL AND o.reason_id != '')", $filter_data['not_reason_ids']);
        }

        // исключить Одобренные, Выданные
        if (!empty($filter_data['not_approved_and_confirmed'])) {
            $where[] = $this->db->placehold("(o.confirm_date IS NULL AND o.approve_date IS NULL)");
        }

        // если изменялась сумма
        if (!empty($filter_data['amount_change'])) {
            $where[] = $this->db->placehold("o.approve_amount IS NOT NULL");
        }

        // полностью зарегистрирован
        if (!empty($filter_data['filter_stage_completed']))
        {
            $where[] = $this->db->placehold("u.additional_data_added = 1");
        }

        // исключаем отвалы
        if (!empty($filter_data['filter_user_registered'])) {
            $where[] = "IF(o.have_close_credits = 0, (
                        u.personal_data_added = 1 AND DATE(u.personal_data_added_date) = DATE(o.date)
                    AND u.address_data_added = 1 AND DATE(u.additional_data_added_date) = DATE(o.date)
                    AND u.accept_data_added = 1 AND DATE(u.accept_data_added_date) = DATE(o.date)
                    AND u.card_added = 1 AND DATE(u.card_added_date) = DATE(o.date)
                    AND u.files_added = 1 AND DATE(u.files_added_date) = DATE(o.date)
                    AND u.additional_data_added = 1 AND DATE(u.additional_data_added_date) = DATE(o.date)), 1)";
        }

        // фильтр по наличию отпарвленного постбека
        if (!empty($filter_data['filter_postback_type'])) {
            $join[] = "LEFT JOIN s_postback p ON p.order_id = o.id";

            // уберем проверку с меток для которых постбек не отправляем
            if (!empty($filter_data['filter_no_validate_postback'])) {
                $where[] = $this->db->placehold("IF(o.utm_source IN (?@), 1, p.type = ?)", $filter_data['filter_no_validate_postback'], $filter_data['filter_postback_type']);
            } else {
                $where[] = $this->db->placehold("p.type = ?", $filter_data['filter_postback_type']);
            }
        }

        // фильтр по пользователям
        if (!empty($filter_data['filter_user_ids'])) {
            $where[] = $this->db->placehold("u.id IN(?@)", array_map('intval', $filter_data['filter_user_ids']));
        }

        if (!empty($filter_data['filter_stage_completed'])
            || !empty($filter_data['filter_user_registered'])
            || !empty($filter_data['filter_user_ids'])) {
            $join[] = "LEFT JOIN s_users u ON u.id = o.user_id";
        }

        $query = strtr($sql, [
            '-- {{join}}' => !empty($join) ? implode(PHP_EOL, $join) : '',
            '-- {{where}}' => !empty($where) ? "AND " . implode(" AND ", $where) : '',
        ]);

        $this->db->query($query);

        if (!empty($fields)) {
            return $this->db->results();
        } else {
            return $return_ids ? $this->db->results('id') : (int)$this->db->result('total');
        }
    }

    /**
     * Сохраняет лог статусов при изменении
     * @param int $order_id
     * @param array $new_data
     * @param array $old_data
     * @return void
     */
    public function addStatusLog(int $order_id, array $new_data, array $old_data)
    {
        $data = [
            'order_id' => $order_id
        ];

        if (!empty($new_data['1c_status']) && $new_data['1c_status'] != $old_data['status_1c']) {
            $data['old_status_1c'] = $old_data['status_1c'];
            $data['status_1c'] = $new_data['1c_status'];
        }

        if (!empty($new_data['status']) && $new_data['status'] != $old_data['status']) {
            $data['old_status'] = $old_data['status'];
            $data['status'] = $new_data['status'];
        }

        // добавим в крон НК при закрытии займа
        if (($data['status_1c'] ?? '') === '6.Закрыт') {
            // проверяем займ на разделение
            $divide_order = $this->getDivideOrderByOrderId($order_id);
            if (!empty($divide_order)) {
                $this->updateStatusDivideOrder($divide_order, $order_id);
            } else {
                $this->addTaskAutoApproveOrder($order_id);
            }
        }

        $query = $this->db->placehold("INSERT INTO s_order_status_logs SET ?%", $data);
        $this->db->query($query);
    }

    /**
     * Генерирует задание cron для автоодобрения
     * @param int $order_id
     * @return void
     */
    public function addTaskAutoApproveOrder(int $order_id)
    {
        $order = $this->get_order($order_id);
        $data_auto_approve = [
            'parent_order_id' => $order_id,
            'user_id' => $order->user_id,
            'status' => $this->orders_auto_approve::STATUS_CRON_NEW,
            'date_cron' => (new DateTime())->format('Y-m-d H:i:s'),
            'validate_scoring' => 1,
        ];
        $this->orders_auto_approve->addAutoApproveNK($data_auto_approve);
    }

    /**
     * Проверяет деленные части, если одна из них выданная ещё, то не позволяем закрыть деленный займ
     *
     * @param $divide_order
     * @param int $order_id
     * @return void
     */
    public function updateStatusDivideOrder($divide_order, int $order_id)
    {
        $additional_order_id = (int)($order_id == $divide_order->main_order_id ? $divide_order->divide_order_id : $divide_order->main_order_id);
        $additional_order = $this->get_order($additional_order_id);

        // если вторая половина не выдана, то выполним действия
        if ($order_id == $divide_order->main_order_id) {
            if (!empty($divide_order->divide_order_id)) {
                if (!empty($additional_order) && $additional_order->status_1c != self::ORDER_1C_STATUS_ISSUED) {
                    if ($additional_order->status_1c != self::ORDER_1C_STATUS_CLOSED) {
                        $res = $this->soap->set_tehokaz($additional_order->id_1c);
                        if ($res === 'OK') {
                            $this->orders->update_order(
                                $additional_order_id,
                                [
                                    'status' => 3,
                                    'reason_id' => $this->reasons::REASON_CLOSED_ONE_DIVIDE_ORDER_REASON_ID,
                                    '1c_status' => self::ORDER_1C_STATUS_REJECTED_TECH,
                                    'reject_date' => date('Y-m-d H:i:s'),
                                ]
                            );
                            $this->addTaskAutoApproveOrder($order_id);
                        }
                    }

                    $this->orders->updateDivideOrder(
                        $divide_order->id,
                        ['status' => $this->orders::DIVIDE_ORDER_STATUS_CLOSED_BY_ONE]
                    );
                }
            } else {
                $this->orders->updateDivideOrder(
                    $divide_order->id,
                    ['status' => $this->orders::DIVIDE_ORDER_STATUS_CLOSED_BY_ONE]
                );
                $this->addTaskAutoApproveOrder($order_id);
            }
        } elseif (!empty($additional_order) && $additional_order->status_1c != self::ORDER_1C_STATUS_ISSUED) {
            $this->orders->updateDivideOrder(
                $divide_order->id,
                ['status' => $this->orders::DIVIDE_ORDER_STATUS_CLOSED]
            );
            $this->addTaskAutoApproveOrder($order_id);
        }
    }

    /**
     * Получает разделенную заявку по главной или разделенной заявке
     * @param int $order_id
     * @return false|int
     */
    public function getDivideOrderByOrderId(int $order_id)
    {
        $query = $this->db->placehold("SELECT * FROM s_divide_order WHERE main_order_id = ? OR divide_order_id = ?", $order_id, $order_id);
        $this->db->query($query);
        return $this->db->result();
    }

    /**
     * Получает информацию из логов статусов
     * В основном метод используется для отчёта Воронка по возвратам НК
     * @param array $filter_data
     * @return array|false
     */
    public function getOrdersByStatusLog(array $filter_data)
    {
        $where = [];
        $select = [];

        $sql = "SELECT 
                        datediff(osl.date_added, o.approve_date) as day_close_after_approve, -- разница между датой выдачи и закрытием
                        u.phone_mobile,
                        (u.last_lk_visit_time > osl.date_added) as visit_lk_after_closed_order -- кто посетил ЛК после закрытия займа
                        -- {{select}}
                    FROM s_order_status_logs osl 
                        LEFT JOIN s_orders o ON o.id = osl.order_id
                        LEFT JOIN s_users u ON u.id = o.user_id
                    WHERE 1 = 1
                    -- {{where}}
                ";

        if (!empty($filter_data['is_funnel_returns'])) {
            $select[] = ",(EXISTS (SELECT * FROM s_orders o2 WHERE o2.date > osl.date_added AND o2.user_id = o.user_id)) as has_order_after_closed, -- кто подал заявку после закрытия займа
                        (EXISTS (SELECT * FROM s_orders o3 WHERE o3.date > osl.date_added AND o3.user_id = o.user_id AND o3.approve_date IS NOT NULL)) as has_approve_order_after_closed, -- кто получил одобрение после закрытия займа
                        (EXISTS (SELECT * FROM s_orders o4 WHERE o4.date > osl.date_added AND o4.user_id = o.user_id AND o4.confirm_date IS NOT NULL)) as has_confirm_order_after_closed -- кто получил займ после закрытия";
        }

        if (!empty($filter_data['days_from'])) {
            $where[] = "datediff(osl.date_added, o.approve_date) >= " . (int)$filter_data['days_from'];
        }

        if (!empty($filter_data['days_to'])) {
            $where[] = "datediff(osl.date_added, o.approve_date) <= " . (int)$filter_data['days_to'];
        }

        if (!empty($filter_data['date_range'])) {
            $where[] = $this->db->placehold(
                "osl.date_added BETWEEN ? AND ?",
                $filter_data['date_range']['filter_date_start'],
                $filter_data['date_range']['filter_date_end']
            );
        }

        if (!empty($filter_data['log_new_status'])) {
            $where[] = $this->db->placehold("osl.status_1c = ?", $filter_data['log_new_status']);
        }

        if (!empty($filter_data['have_close_credits'])) {
            $where[] = "o.have_close_credits = " . (int)$filter_data['have_close_credits'];
        }

        $query = strtr($sql, [
            '-- {{select}}' => !empty($select) ? implode(PHP_EOL, $select) : '',
            '-- {{where}}' => !empty($where) ? "AND " . implode(" AND ", $where) : '',
        ]);

        $this->db->query($query);
        return $this->db->results();
    }

    /**
     * Проверяет, стал ли НК ПК + взял ли займ после того как стал ПК
     * @param array $order_ids
     * @return int
     */
    public function hasNkToPkByOrderIds(array $order_ids, array $filter_data = []): int
    {
        $where = [];

        $sql = "    SELECT 
                        COUNT(*) as total 
                    FROM s_orders o WHERE o.id IN (?@)
                    AND EXISTS(
                        SELECT * FROM s_orders o2 
                                 WHERE o2.date > o.date 
                                   AND o2.user_id = o.user_id
                                   AND o2.confirm_date IS NOT NULL 
                                   -- {{where}} 
                        )";

        if (!empty($filter_data['filter_date_order'])) {
            $where[] = $this->db->placehold("DATE(o2.date) BETWEEN ? AND ?", $filter_data['filter_date_order']['filter_date_start'], $filter_data['filter_date_order']['filter_date_end']);
        }

        $query = strtr($sql, [
            '-- {{where}}' => !empty($where) ? "AND " . implode(" AND ", $where) : '',
        ]);

        $query = $this->db->placehold($query, $order_ids);
        $this->db->query($query);
        return (int)$this->db->result('total');
    }

    /**
     * Генерируем сумму вознаграждения
     * временный метод, до тех пор пока не перенесем в БД функционал
     * @deprecated
     * @param $order
     * @return int
     */
    public function getPayoutGrade($order): int
    {
        switch ($order->utm_source) {
            case 'leadcraft':
            case 'beegl':
                $score = $order->scorista_ball;
                if ($score < 600) {
                    $price = 1500;
                } elseif ($score >= 600 & $score < 700) {
                    $price = 2000;
                } elseif ($score >= 700 & $score < 750) {
                    $price = 2500;
                } else {
                    $price = 3000;
                }
                break;
            case 'mvp':
                $score = $order->scorista_ball;
                if ($score < 600) {
                    $price = 1250;
                } elseif ($score >= 600 & $score < 700) {
                    $price = 1700;
                } elseif ($score >= 700 & $score < 750) {
                    $price = 2100;
                } else {
                    $price = 2500;
                }
                break;
            case 'leadgid':
            case 'guruleads':
            case 'LW':
            case 'LW2':
            case 'unicom24':
            case 'cityads':
            case 'leadstech':
                $price = 2700;
                break;
            case 'bankiru':
                $price = 2900;
                break;
            case 'cf':
                $price = 200;
                break;
            case 'c2m':
                $price = $order->webmaster_id == 174 ? 3000 : 2100;
                break;
            default:
                $price = 0;
        }

        return $price;
    }

