    /**
     * Генерирует новую разделенную заявку от главной и одобряет ее
     * @param int $divide_order_id
     * @param int $amount_order
     * @param bool $send_sms
     * @return string
     */
    public function generate_divide_order(int $divide_order_id, int $amount_order = 0, bool $send_sms = true): string
    {
        $status = 'NEW';
        $divide_order = $this->getDivideOrderById($divide_order_id);
        $order_id = $divide_order->main_order_id;

        $old_order = $this->orders->get_order($order_id);
        $divide_pre_order = $this->getDividePreOrder($order_id);

        // вычислим период для новой заявки
        /*$order_confirm_date = $old_order->confirm_date ?: $this->getConfirmeDate($order_id);
        $confirm_date = new \DateTime($order_confirm_date);
        $confirm_date->setTime(0, 0);

        $now_date = new DateTime();
        $interval_diff = $confirm_date->diff($now_date);

        // получим период для будущей заявки
        $period = max($old_order->period - $interval_diff->days, 1);*/
        $period = 31;
        $amount = $amount_order ?: $divide_pre_order->amount;
        $percent = self::BASE_PERCENTS;

        $new_order_data = [
            'amount' => $amount,
            'period' => $period,
            'percent' => $percent,
            'status' => self::ORDER_STATUS_CRM_NEW,
            'card_id' => $old_order->card_id,
            'user_id' => $old_order->user_id,
            'first_loan' => $old_order->first_loan,
            'date' => date('Y-m-d H:i:s'),
            'utm_source' => self::UTM_SOURCE_DIVIDE_ORDER,
            'utm_medium' => 'CRM',
            'utm_campaign' => $old_order->utm_campaign,
            'utm_content' => $old_order->utm_content,
            'utm_term' => $old_order->utm_term,
            'webmaster_id' => $old_order->webmaster_id,
            'order_uid' => exec($this->config->root_dir . 'generic/uidgen'),
            'b2p' => $old_order->b2p,
            'manager_id' => $this->managers::MANAGER_SYSTEM_ID,
            'is_user_credit_doctor' => $old_order->is_user_credit_doctor,
            'have_close_credits' => $old_order->have_close_credits,
        ];

        $params = [
            'utm_source' => self::UTM_SOURCE_DIVIDE_ORDER,
            'utm_medium' => 'CRM',
        ];

        if ($new_order_id = $this->orders->add_order($new_order_data)) {
            $this->updateDivideOrder($divide_order_id, [
                'divide_order_id' => $new_order_id,
                'status' => self::DIVIDE_ORDER_STATUS_ADD_NEW_ORDER,
            ]);

            $soap_zayavka = $this->soap->soap_repeat_zayavka(
                $amount,
                $period,
                $old_order->user_id,
                $old_order->card_id,
                null,
                $params
            );
            if (empty($soap_zayavka->return->id_zayavka)) {
                $this->orders->update_order($new_order_id, [
                    'status' => 3,
                    'note' => strval($soap_zayavka->return->Error)
                ]);

                $this->updateDivideOrder($divide_order_id, ['status' => self::DIVIDE_ORDER_STATUS_ERROR]);
                $status = 'ERROR_SEND_TO_1C';
            } else {
                $this->orders->update_order($new_order_id, [
                    '1c_id' => $soap_zayavka->return->id_zayavka,
                    'accept_date' => date('Y-m-d H:i:s'),
                ]);
                $this->soap->set_order_complete($new_order_id);
                $status = 'COMPLETED_TO_1C';

                // тут же автоматически одобряем
                $manager = $this->managers->get_manager($old_order->manager_id);
                $response_1c = $this->soap->update_status_1c(
                    $soap_zayavka->return->id_zayavka,
                    'Одобрено',
                    $manager->name_1c,
                    $amount,
                    $percent,
                    '',
                    0,
                    $period
                );
                if ($response_1c === 'OK') {
                    $this->orders->update_order($new_order_id, [
                        'status' => self::ORDER_STATUS_CRM_APPROVED,
                        '1c_status' => self::ORDER_1C_STATUS_APPROVED,
                        'approve_date' => date('Y-m-d H:i:s'),
                    ]);

                    $this->updateDivideOrder($divide_order_id, ['status' => self::DIVIDE_ORDER_STATUS_APPROVED]);

                    if ($send_sms) {
                        // Отправим СМС об одобрении займа
                        $user = $this->users->get_user($old_order->user_id);
                        $this->smssender->sendApprovedSms($user, $new_order_id, $amount);
                        $this->finroznica->send_user($user);
                    }

                    $status = 'APPROVE_TO_1C';
                }
            }
        }

        return $status;
    }

    /**
     * Orders::check_issued_order()
     * Проверяет есть ли открытые займы у клиента и можно ли ему выдать займ по заявке
     * 0 - можно выдавать, 1 - нельзя выдавать
     *
     * @param array|stdClass $order Заявка, которую выдаём
     * @return int 0|1
     */
    public function check_issued_order($order)
    {
        $order = (array)$order;

        $issued_loans = $this->soap->DebtForFIO($order);
        $issued_loans = array_filter($issued_loans, function($var){
            return $var->ОстатокОД > 0;
        });

        if (count($issued_loans) >= 3) {
            return 1;
        }

        foreach ($issued_loans as $k => $issued_loan) {
            $current_organization_id = $this->organizations->get_organization_id_by_inn($issued_loan->{'ОрганизацияИНН'});
            // Если заявка от этой МКК уже выдана
            if ($current_organization_id == $order['organization_id']) {
                return 1;
            }
            
            if ($issued_loan->contract = $this->contracts->get_contract_by_params(['number' => $issued_loan->{'НомерЗайма'}])) {
                $issued_loan->order = $this->get_order_short($issued_loan->contract->order_id);

                //  Если открытый займ - это кросс-ордер, а текущий займ родительский, то разрешаем выдачу
                if ($issued_loan->order->utm_source == self::UTM_SOURCE_CROSS_ORDER && $issued_loan->order->utm_medium == $order['order_id']) {
                    unset($issued_loans[$k]);
                    continue;
                }

                //  Если текущий займ - это кросс-ордер
                if ($order['utm_source'] == self::UTM_SOURCE_CROSS_ORDER) {
                    // Открытый займ родительский, разрешаем выдачу
                    if ($order['utm_medium'] == $issued_loan->order->id) {
                        unset($issued_loans[$k]);
                        continue;
                    }

                    // Открытый займ - кросс-ордер от того же родителя, разрешаем выдачу
                    if (
                        $issued_loan->order->utm_source == self::UTM_SOURCE_CROSS_ORDER &&
                        $issued_loan->order->utm_medium == $order['utm_medium']
                    ) {
                        unset($issued_loans[$k]);
                        continue;
                    }
                }


                // Если текущий займ - это автозаявка, а открытый займ это кросс-ордер И они от разных МКК,
                // то разрешаем выдачу
                if (
                    $order['utm_source'] === self::UTM_SOURCE_CRM_AUTO_APPROVE &&
                    $issued_loan->order->utm_source === self::UTM_SOURCE_CROSS_ORDER &&
                    (int)$order['organization_id'] !== (int)$issued_loan->order->organization_id
                ) {
                    unset($issued_loans[$k]);
                }
            }
        }
        if (empty($issued_loans))
            return 0;

        return 1;
    }

