    public function getApprovedOrders($start, $end)
    {
        $query = $this->db->placehold("
        SELECT 
            s_orders.id AS order_id, 
            s_orders.amount, 
            s_users.firstname AS client_name, 
            s_users.phone_mobile AS phone,
            COALESCE(NULLIF(s_time_zones.timezone, ''), '+00:00') AS UTC, 
            s_users.gender  
        FROM s_orders
        JOIN s_users ON s_orders.user_id = s_users.id
        LEFT JOIN s_time_zones ON s_users.timezone_id = s_time_zones.time_zone_id
        WHERE 
            s_orders.status = 2 
            AND s_orders.`1c_status` = '3.Одобрено'
            AND s_orders.approve_date BETWEEN ? AND ?
            AND NOT EXISTS (
                SELECT 1 FROM s_user_data sud
                WHERE sud.user_id = s_users.id
                AND sud.key = 'disable_approved_order_calls'
                AND sud.value = '1'
            )
            AND NOT EXISTS (
                SELECT 1 FROM s_orders o2
                WHERE o2.user_id = s_orders.user_id
                AND o2.id != s_orders.id
                AND o2.organization_id != s_orders.organization_id
                AND o2.status = 2
                AND o2.`1c_status` = '3.Одобрено'
            )
        GROUP BY s_orders.user_id
    ");
        $this->db->query($query, $start, $end);
        return $this->db->results();
    }

