    public function get_short_orders($filter = array())
    {
        try {
            $id_filter = '';
            $search_filter = '';
            $limit = $filter['limit'] ?? 10000;
            $sort = $filter['sort'] ?? 'o.1c_status DESC';

            // Фильтр по ID заказа
            if (!empty($filter['id'])) {
                $id_filter = $this->db->placehold("AND o.id IN (?@)", array_map('intval', (array)$filter['id']));
            }

            // Фильтры для поиска
            if (!empty($filter['order_id'])) {
                $search_filter .= $this->db->placehold(' AND o.id = ?', (int)$filter['order_id']);
            }
            if (!empty($filter['manager_id'])) {
                $search_filter .= $this->db->placehold(' AND o.manager_id = ?', (int)$filter['manager_id']);
            }
            if (!empty($filter['user_id'])) {
                $search_filter .= $this->db->placehold(' AND o.user_id = ?', (int)$filter['user_id']);
            }

            $query = $this->db->placehold("
            SELECT STRAIGHT_JOIN
                o.id,
                o.contract_id,
                o.manager_id,
                o.status,
                o.date,
                o.user_id,
                o.amount,
                o.period,
                o.percent,
                o.first_loan,
                o.1c_id AS id_1c,
                o.1c_status AS status_1c,
                o.loan_type,
                o.payment_period,
                o.organization_id,
                o.order_uid
            FROM __orders AS o
            LEFT JOIN __users AS u ON u.id = o.user_id
            WHERE 1
                $id_filter
                $search_filter
            ORDER BY $sort
            LIMIT ?
        ", $limit);

            $this->db->query($query);

            return $this->db->results();
        } catch (Exception $e) {
            error_log('Error fetching short orders: ' . $e->getMessage());
            return array();
        }
    }

    /**
     * Одобрение НК заявки, если прошли УПРИД и скориста или акси
     * @param $orderId
     * @return void
     */
    public function priorApprove($orderId)
    {
        $new_flow_enabled = $this->settings->new_flow_enabled;
        if (empty($new_flow_enabled))
            return;

        $order = $this->orders->get_order($orderId);

        if ($order->have_close_credits != 0)
            return;
        if (in_array($order->utm_source, self::UTM_SOURCES_NOT_FOR_PRIOR_APPROVE))
            return;

        // Заявка уже одобрена или по ней есть отказ
        if ($order->status != $this->orders::ORDER_STATUS_CRM_NEW)
            return;

        // Только для заявок до 15к
        if ($order->amount > 15000 || $order->approve_amount > 15000)
            return;

        $successUprid = $this->scorings->getLastScoring([
            'user_id' => $order->user_id,
            'type' => $this->scorings::TYPE_UPRID,
            'status' => $this->scorings::STATUS_COMPLETED,
            'success' => $this->scorings::SCORING_STATUS_SUCCESS,
        ]);
        // Только для тех, у кого удачно прошёл УПРИД
        if (empty($successUprid))
            return;

        $successScorista = $this->scorings->getLastScoring([
            'order_id' => $order->order_id,
            'type' => $this->scorings::TYPE_SCORISTA,
            'status' => $this->scorings::STATUS_COMPLETED,
            'success' => $this->scorings::SCORING_STATUS_SUCCESS,
        ]);
        $successAxi = $this->scorings->getLastScoring([
            'order_id' => $order->order_id,
            'type' => $this->scorings::TYPE_AXILINK_2,
            'status' => $this->scorings::STATUS_COMPLETED,
            'success' => $this->scorings::SCORING_STATUS_SUCCESS,
        ]);

        // Заявку должна одобрить или скориста или акси
        if (empty($successScorista) && empty($successAxi))
            return;

        // ОДОБРЕНИЕ
        // Помечаем заявку для аналитики
        $this->order_data->set($order->order_id, 'new_nk_flow', true);

        $this->approveOrder($orderId);
    }

    public function approveOrder($orderId)
    {
        $update = [
            'status' => self::ORDER_STATUS_CRM_APPROVED,
            'manager_id' => $this->managers::MANAGER_SYSTEM_ID,
            'approve_date' => date('Y-m-d H:i:s'),
        ];

        //region Логирование изменения статуса
        $oldOrder = $this->orders->get_order($orderId);
        $oldValues = array();
        foreach ($update as $key => $val)
            if ($oldOrder->$key != $val)
                $oldValues[$key] = $oldOrder->$key;

        $logUpdate = array();
        foreach ($update as $k => $u)
            if (isset($oldValues[$k]))
                $logUpdate[$k] = $u;

        $this->changelogs->add_changelog(array(
            'manager_id' => $this->managers::MANAGER_SYSTEM_ID,
            'created' => date('Y-m-d H:i:s'),
            'type' => 'status',
            'old_values' => serialize($oldValues),
            'new_values' => serialize($logUpdate),
            'order_id' => $orderId,
        ));
        //endregion

        $this->orders->update_order($orderId, $update);

        $order = $this->orders->get_order($orderId);
        $site_id = $this->users->get_site_id_by_user_id($order->user_id);
        $manager = $this->managers->get_manager($this->managers::MANAGER_SYSTEM_ID);

        $this->soap->update_status_1c($order->id_1c, 'Одобрено', $manager->name_1c, $order->amount, $order->percent, '', 0, $order->period);

        //region Отправка СМС
        if ($smsApproveStatus = $this->settings->sms_approve_status) {
            $template = $this->sms->get_template($this->sms::AUTO_APPROVE_TEMPLATE_NOW, $site_id);
            $text_message = strtr($template->template, [
                '{{firstname}}' => $order->firstname,
                '{{amount}}' => $order->approve_amount ?: $order->amount,
            ]);

            $text = $text_message;
            $resp = $status = $this->smssender->send_sms($order->phone_mobile, $text, $site_id);
            $this->sms->add_message([
                'user_id' => $order->user_id,
                'order_id' => $order->order_id,
                'phone' => $order->phone_mobile,
                'message' => $text_message,
                'created' => date('Y-m-d H:i:s'),
                'send_status' => $resp[1],
                'delivery_status' => '',
                'send_id' => $resp[0],
                'type' => $this->smssender::TYPE_AUTO_APPROVE_ORDER,
            ]);

            if ($status) {
                $this->db->query("INSERT INTO sms_log SET phone='" . $order->phone_mobile . "', status='" . $status[1] . "', dates='" . date("Y-m-d H:i:s") . "', sms_id='" . $status[0] . "'");
            }
        }
        //endregion

        $this->users->update_loan_funnel_report(
            (int)$order->order_id,
            (int)$order->user_id,
            [
                'approved' => true,
                'approved_date' => date("Y-m-d")
            ]
        );

        $this->finroznica->send_user($this->users->get_user($oldOrder->user_id));
        if ($order->utm_source == 'vibery'){
            $this->post_back->sendApproveOrder($order);
        }

        $this->cross_orders->create($order->order_id);
    }

