    /**
     * Переводит заявку в отказ
     *
     * @param stdClass $order
     * @param int $reasonId
     * @return void
     */
    public function rejectOrder(stdClass $order, int $reasonId): void
    {
        $orderId = $order->order_id ?? $order->id;
        $order1cId = $order->id_1c ?? $order->{'1c_id'};

        $tech_manager = $this->managers->get_manager($this->managers::MANAGER_SYSTEM_ID);
        $update_order = array(
            'status' => $this->orders::ORDER_STATUS_CRM_REJECT,
            'manager_id' => $tech_manager->id,
            'reason_id' => $reasonId,
            'reject_date' => date('Y-m-d H:i:s')
        );
        $this->orders->update_order($orderId, $update_order);
        $this->leadgid->reject_actions($orderId);

        $changeLogs = Helpers::getChangeLogs($update_order, $order);

        $this->changelogs->add_changelog(array(
            'manager_id' => $tech_manager->id,
            'created' => date('Y-m-d H:i:s'),
            'type' => 'status',
            'old_values' => serialize($changeLogs['old']),
            'new_values' => serialize($changeLogs['new']),
            'order_id' => $orderId,
            'user_id' => $order->user_id,
        ));

        $reason = $this->reasons->get_reason($reasonId);
        $this->soap->update_status_1c($order1cId, $this->orders::ORDER_1C_STATUS_REJECTED, $tech_manager->name_1c, 0, 1, $reason->admin_name);

        if (!empty($order->is_user_credit_doctor)) {
            $this->soap1c->send_credit_doctor($order1cId);
        }

        try {
            $this->soap->send_order_manager($order1cId, $tech_manager->name_1c);
        } catch (Throwable $error) {
            $this->logging(__METHOD__, '', 'Ошибка при отказе по заявке', ['order' => $order, 'error' => $error], self::LOG_FILE);
        }

        $this->soap->block_order_1c($order1cId, 0);

        // отправляем заявку на кредитного доктора
        $this->cdoctor->send_order($orderId);
    }

    public function isCrossOrder(stdClass $order): bool
