    /**
     * Проверяет, нужно ли применить отсрочку выдачи для заказа
     *
     * Условия отсрочки:
     * - Сумма 50 000 рублей и более
     * - С момента подписания прошло менее 4 часов
     * - Статус = 8 (Подписан)
     *
     * @param stdClass $order Объект заказа
     * @return bool True если нужна отсрочка, False если можно выдавать
     */
    public function shouldDelayIssuance(stdClass $order): bool
    {
        // Проверяем статус
        if ((int)$order->status !== 8) {
            return false;
        }

        $contract = $this->contracts->get_contract_by_params(['order_id' => $order->order_id]);

        if (empty($contract)) {
            return false;
        }

        // Проверяем сумму (50 000 рублей и больше)
        if ((int)$contract->amount < 50000) {
            return false;
        }

        // Проверяем время с момента подписания
        if (empty($order->confirm_date)) {
            return false;
        }

        // Если прошло менее 4 часов - применяем отсрочку
        return $this->getHoursAfterConfirm($order->confirm_date) < 4;
    }

    /**
     * Получаем количество часов, прошедших с момента подписания заявки
     *
     * @param $confirm_date дата подписания заявки
     * @return int Количество часов, прошедших с момента подписания
     */
    public function getHoursAfterConfirm($confirm_date): int
    {
        return (time() - strtotime($confirm_date)) / 3600;
    }

    public function isRefinanceOrder(object $order): bool
    {
