    }

    /**
     * Проверка готовности к выдаче с учётом:
     *  - BLACKLIST
     *  - до двух попыток UPRID.
     *
     * @param object $order Ожидаются: $order->order_id, $order->user_id
     *
     * @return array{
     *     ready: bool|null,
     *     reason: array{
     *         code: ?string,
     *         message: ?string
     *     }
     * }
     */
    public function readyForPayout(object $order): array
    {
        if ($this->user_data->read($order->user_id, $this->user_data::TEST_USER)) {
            return $this->buildPayoutResult(true);
        }
        $inProgressStatuses = [
            $this->scorings::STATUS_NEW,
            $this->scorings::STATUS_PROCESS,
            $this->scorings::STATUS_WAIT,
        ];

        // 1) Сначала проверяем BLACKLIST
        $blacklistResult = $this->checkBlacklistPayoutDecision($order);

        // Если BLACKLIST вернул не "готов к выдаче" — это финальный результат (wait / reject)
        if ($blacklistResult['ready'] !== true) {
            return $blacklistResult;
        }

        if ($this->settings->terrorist_check_before_loan_issuance_enabled){
            $terroristResult = $this->checkTerroristPayoutDecision($order, $inProgressStatuses);
            if ($terroristResult['ready'] !== true) {
                return $terroristResult;
            }
        }

        // 2) Если UPRID отключен — после успешного BLACKLIST можем выдавать
        if (!$this->settings->check_uprid_enabled) {
            return $this->buildPayoutResult(true);
        }

        // 3) Проверяем UPRID
        return $this->checkUpridPayoutDecision($order, $inProgressStatuses);
    }

    /**
     * Строит единый формат результата.
     *
     * @param bool|null   $ready
     * @param string|null $code
     * @param string|null $message
     *
     * @return array{
     *     ready: bool|null,
     *     reason: array{
     *         code: ?string,
     *         message: ?string
     *     }
     * }
     */
    private function buildPayoutResult(?bool $ready, ?string $code = null, ?string $message = null): array
    {
        return [
            'ready'  => $ready,
            'reason' => [
                'code'    => $code,
                'message' => $message,
            ],
        ];
    }


    /**
     * Проверка TerroristCheck перед выдачей:
     * - если скоринга нет -> создать, сразу выполнить, вернуть результат
     * - если скоринг есть и он NEW/PROCESS/WAIT -> принудительно выполнить сейчас
     * - если COMPLETED -> вернуть результат
     *
     * Fail-closed: если скоринг не завершился/ошибка — выдачу запрещаем.
     *
     * @param object $order
     * @param array  $inProgressStatuses
     * @return array
     */
    private function checkTerroristPayoutDecision(object $order, array $inProgressStatuses): array
    {
        // 0) Если тип скоринга отключён — выдача разрешена
        $terroristType = $this->scorings->get_type($this->scorings::TYPE_TERRORIST_CHECK);
        if (empty($terroristType) || empty($terroristType->active)) {
            return $this->buildPayoutResult(true);
        }

        $scoringId = (int)$this->scorings->add_scoring([
            'type'     => $this->scorings::TYPE_TERRORIST_CHECK,
            'user_id'  => (int)$order->user_id,
            'order_id' => (int)$order->order_id,
            'status'   => $this->scorings::STATUS_NEW,
        ]);
        try {
            // запуск скоринга синхронно
            $this->terrorist->run_scoring($scoringId);
            $fresh = $this->scorings->get_scoring($scoringId);
            if (empty($fresh)) {
                return $this->buildPayoutResult(
                    false,
                    'TERRORIST_ERROR',
                    'Ошибка запуска скоринга террористов'
                );
            }

            $status  = (int)$fresh->status;
            $success = (int)$fresh->success;

            if ($status === $this->scorings::STATUS_COMPLETED && $success === $this->scorings::SCORING_STATUS_SUCCESS) {
                return $this->buildPayoutResult(true);
            }

            if ($status === $this->scorings::STATUS_COMPLETED && $success !== $this->scorings::SCORING_STATUS_SUCCESS) {
                return $this->buildPayoutResult(
                    false,
                    'TERRORIST_DENY',
                    'Клиент найден в террористических списках'
                );
            }

            // ERROR / прочее — fail-closed
            return $this->buildPayoutResult(
                false,
                'TERRORIST_ERROR',
                'Ошибка проверки террористических списков'
            );

        } catch (\Throwable $e) {
            $this->logging(
                __METHOD__,
                '',
                'Ошибка синхронного запуска TerroristCheck перед выдачей',
                ['order' => $order, 'scoringId' => $scoringId, 'error' => $e->getMessage()],
                self::LOG_FILE
            );

            return $this->buildPayoutResult(
                false,
                'TERRORIST_ERROR',
                'Ошибка проверки террористических списков'
            );
        }
    }



    /**
     * Проверка BLACKLIST перед выдачей:
     *  - Локальный ЧС → отказ
     *  - 1С: если ответила — учитываем результат
     *
     * @param object $order
     * @return array
     */
    private function checkBlacklistPayoutDecision(object $order): array
    {
        $blacklistType = $this->scorings->get_type($this->scorings::TYPE_BLACKLIST);

        // Если скоринг ЧС отключён — выдача разрешена
        if (empty($blacklistType) || empty($blacklistType->active)) {
            return $this->buildPayoutResult(true);
        }
        /**
         * 1) Локальный CRM-чёрный список
         */
        if ($this->blacklist->in($order->user_id)) {
            return $this->buildPayoutResult(
                false,
                'BLACKLIST_LOCAL_DENY',
                'Клиент находится в чёрном списке'
            );
        }

        /**
         * 2) Проверка ЧС в 1С
         */
        if (!empty($order->user_uid)) {
            $check = $this->blacklist->checkIsUserIn1cBlacklistSafe($order->user_uid);

            if ($check['ok'] === true) {
                if (!empty($check['in_blacklist'])) {
                    return $this->buildPayoutResult(
                        false,
                        'BLACKLIST_1C_DENY',
                        'Клиент находится в чёрном списке 1С'
                    );
                }
            }
        }

        /**
         * 3) Клиент чист → выдача разрешена
         */
        return $this->buildPayoutResult(true);
    }



    /**
     * Проверка UPRID перед выдачей.
     *
     * Возвращает:
     *  - ready = true  → UPRID пройден
     *  - ready = null  → ждём завершения / создаём новую попытку
     *  - ready = false → отказ по UPRID (2 терминальных неудачи)
     *
     * @param object $order
     * @param array  $inProgressStatuses
     *
     * @return array
     */
    private function checkUpridPayoutDecision(object $order, array $inProgressStatuses): array
    {
        $attempts = $this->scorings->get_scorings([
            'order_id' => (int) $order->order_id,
            'type'     => $this->scorings::TYPE_UPRID,
            'sort'     => 'id_date_desc',
        ]);

        // Нет попыток — создаём первую и ждём
        if (empty($attempts)) {
            $scoringId = $this->scorings->add_scoring([
                'type'     => $this->scorings::TYPE_UPRID,
                'user_id'  => (int) $order->user_id,
                'order_id' => (int) $order->order_id,
                'status'   => $this->scorings::STATUS_NEW,
            ]);

            $this->logging(
                __METHOD__,
                '',
                'Не найден УПРИД скоринг при проверке перед выдачей, создается новый',
                ['order' => $order, 'scoringId' => $scoringId],
                self::LOG_FILE
            );

            return $this->buildPayoutResult(
                null,
                'UPRID_WAIT',
                'Ожидание завершения скоринга UPRID'
            );
        }

        $terminalFailures = 0;

        foreach ($attempts as $index => $scoring) {
            $status  = (int) $scoring->status;
            $success = (int) $scoring->success;

            // Есть активная попытка — ждём
            if (in_array($status, $inProgressStatuses, true)) {
                $this->logging(
                    __METHOD__,
                    '',
                    'Выполняется скоринг УПРИД, найдено при проверке перед выдачей',
                    ['order' => $order, 'scoringId' => $scoring->id],
                    self::LOG_FILE
                );

                return $this->buildPayoutResult(
                    null,
                    'UPRID_WAIT',
                    'Ожидание завершения скоринга UPRID'
                );
            }

            // Последняя (самая свежая) COMPLETED + SUCCESS → UPRID пройден
            if (
                $index === 0
                && $status === $this->scorings::STATUS_COMPLETED
                && $success === $this->scorings::SCORING_STATUS_SUCCESS
            ) {
                return $this->buildPayoutResult(true);
            }

            // Терминальный, но не успешный → считаем неудачной попыткой
            $isSuccess = $status === $this->scorings::STATUS_COMPLETED
                && $success === $this->scorings::SCORING_STATUS_SUCCESS;

            if (!$isSuccess && !in_array($status, $inProgressStatuses, true)) {
                $terminalFailures++;

                if ($terminalFailures >= $this->uprid::MAX_UPRID_ERROR_ATTEMPTS) {
                    $this->logging(
                        __METHOD__,
                        '',
                        'Отказан скоринг UPRID при проверке перед выдачей',
                        ['order' => $order, 'scorings' => $attempts],
                        self::LOG_FILE
                    );

                    return $this->buildPayoutResult(
                        false,
                        'UPRID_REJECT',
                        'Отказ по результатам скоринга UPRID'
                    );
                }
            }
        }

        // Активных нет, лимит не исчерпан — создаём ещё одну попытку и ждём
        $this->scorings->add_scoring([
            'type'     => $this->scorings::TYPE_UPRID,
            'user_id'  => (int) $order->user_id,
            'order_id' => (int) $order->order_id,
            'status'   => $this->scorings::STATUS_NEW,
        ]);

        return $this->buildPayoutResult(
            null,
            'UPRID_WAIT',
            'Ожидание завершения скоринга UPRID'
        );
    }

    /**
     * Проверяет закрыт ли займ по s_orders.status и s_orders.`1c_status`
     * Обновить 1c_status можно так $response = $this->soap->check_order_1c($order->id_1c);
     *
     * @param stdClass $order
     * @return bool
     */
    public function isOrderClosed(stdClass $order): bool
    {
        $closedStatuses = [
            $this->orders::ORDER_STATUS_CRM_ISSUED,
            $this->orders::ORDER_STATUS_CRM_REJECT
        ];

        $closed1CStatuses = [
            $this->orders::ORDER_1C_STATUS_CLOSED,
            $this->orders::ORDER_1C_STATUS_REJECTED_2,
            $this->orders::ORDER_1C_STATUS_REJECTED_TECH
        ];

        $order1CStatus = $order->status_1c ?: $order->{'1c_status'};
        if (in_array($order->status, $closedStatuses) && in_array($order1CStatus, $closed1CStatuses)) {
            return true;
        }

        return false;
    }

    public function getCountOfUniqueClients()
    {
        $sql = "SELECT COUNT(DISTINCT user_id) as count FROM __orders WHERE complete IS NOT NULL";

        $this->db->query($sql);

        return $this->db->result()->count;
    }

    public function checkAreOrdersClosedWithUpdate1cStatus(array $orders): bool
    {
        $ordersToUpdate1cStatus = [];
        foreach ($orders as $order) {
            if (!$this->isOrderClosed($order)) {
                $ordersToUpdate1cStatus[] = $order;
            }
        }

        if (empty($ordersToUpdate1cStatus)) {
            return true;
        }

        $ordersId = array_column($ordersToUpdate1cStatus, 'order_id');
        $orders1cId = array_column($ordersToUpdate1cStatus, 'id_1c');

        try {
            $response = $this->soap->check_order_1c_array($orders1cId);
        } catch (Throwable $error) {
            $this->logging(__METHOD__, '', 'Ошибка при получении статусов из 1C', ['orders_id' => $ordersId, 'error' => $error], self::LOG_FILE);
            return false;
        }

        $this->logging(__METHOD__, '', 'Получен $response при получении статусов из 1C', ['orders_id' => $ordersId, 'response' => $response], self::LOG_FILE);

        if (empty($response)) {
            return false;
        }

        if ($this->areOrdersClosedBy1cResponse($ordersToUpdate1cStatus, $response)) {
            return true;
        }

        return false;
    }

    private function areOrdersClosedBy1cResponse(array $orders, stdClass $response): bool
    {
        foreach ($orders as $order) {

            if (isset($response->Результат->НомерЗаявки)) {
                if ($order->id_1c !== $response->Результат->НомерЗаявки) {
                    continue;
                }

                // Если 1c_status в БД отличается от статуса, полученного из 1C, то обновляем его
                if (!empty($response->Результат->Статус) && $order->status_1c !== $response->Результат->Статус) {
                    $this->update_order($order->order_id, [
                        '1c_status' => $response->Результат->Статус,
                        'comment' => $response->Результат->Комментарий,
                    ]);

                    $order->status_1c = $response->Результат->Статус;
                }

                if (!$this->isOrderClosed($order)) {
                    $this->logging(__METHOD__, '', 'У клиента есть открытый займ', ['incomplete_order' => $order], self::LOG_FILE);
                    return false;
                }
                break;
            }

            foreach ($response->Результат as $responseItem) {
                if ($order->id_1c !== $responseItem->НомерЗаявки) {
                    continue;
                }

                // Если 1c_status в БД отличается от статуса, полученного из 1C, то обновляем его
                if (!empty($responseItem->Статус) && $order->status_1c !== $responseItem->Статус) {
                    $this->update_order($order->order_id, [
                        '1c_status' => $responseItem->Статус,
                        'comment' => $responseItem->Комментарий,
                    ]);

                    $order->status_1c = $responseItem->Статус;
                }

                if (!$this->isOrderClosed($order)) {
                    $this->logging(__METHOD__, '', 'У клиента есть открытый займ', ['incomplete_order' => $order], self::LOG_FILE);
                    return false;
                }
                break;
            }
        }

        return true;
    }

    /**
     * Максимальная сумма займа без учёта допов
     *
     * @param object $order
     * @return int Всегда >= 0
     */
    public function getMaxAmountWithoutDops($order): int
    {
        $baseAmount = (int)$this->settings->il_max_amount_without_dops;

        $isDopsDisabled = $this->order_data->read(
            $order->order_id,
            OrderData::DISABLE_ADDITIONAL_SERVICE_ON_ISSUE
        );

        if ($isDopsDisabled) {
            return $baseAmount;
        }

        $dopsTotal = (int)$this->credit_doctor->getAmountCreditDoctor($order->amount)
                   + StarOracle::AMOUNT;

        return max(0, $baseAmount - $dopsTotal);
    }

    public function getWaitingVirtualCardOrders()
    {
        $this->db->query("
            SELECT 
				o.id,
				o.user_id,
				o.card_type,
				o.status
            FROM s_orders as o
            WHERE status = ?
            AND card_type = ?",
            self::STATUS_WAIT_VIRTUAL_CARD,
            self::CARD_TYPE_VIRT
        );

        return $this->db->results();
    }
